glus
    .map(function (g) {
      if (!g || typeof g !== 'object') return '';
      return String(/** @type {any} */ (g).time || '') + '@' + String(/** @type {any} */ (g).value || '');
    })
    .join

bombas
    .map(function (b) {
      if (!b || typeof b !== 'object') return '';
      return String(/** @type {any} */ (b).time || '') + '@' + String(/** @type {any} */ (b).value || '');
    })
    .join

tabs
    .map(function (t) {
      var has = eaChartTabHasData(slotData, t.id);
      return (
        '<button type="button" role="tab" class="ea-charts-tab" data-ea-chart-tab="' +
        t.id +
        '" aria-selected="false"' +
        (has ? '' : ' disabled') +
        '>' +
        t.label +
        '</button>'
      );
    })
    .join

VITAL_FAMILIES.filter(function (fam) {
    return !!slotData['vital:' + fam.id];
  })
    .map(function (fam) {
      return (
        '<button type="button" role="tab" class="ea-vitals-family-btn" data-ea-vital-family="' +
        fam.id +
        '" aria-selected="false">' +
        fam.title +
        '</button>'
      );
    })
    .join

barr
        .map(function (e) {
          if (!e || typeof e !== 'object') return null;
          var v = Number(/** @type {any} */ (e).value);
          var u = Number(/** @type {any} */ (e).units);
          if (!Number.isFinite(v)) return null;
          return {
            value: v,
            units: Number.isFinite(u) ? u : 0,
            time: /** @type {any} */ (e).time != null ? String(/** @type {any} */ (e).time) : undefined,
          };
        })
        .filter

MED_FIELD_KEYS.map(function (key) {
